int get_average(int score[], int n) {
    int i, sum;
    for(i = 0; i < n; i++)
        sum += score[i];
    return sum / n;
}
void main(void) {
    int score[3] = { 1, 2, 5 };
    printf("%d\n", get_average(score, 3));
}

